    const bureau = $(tab).attr('data-bureau') || $(tab).text();
    const content = $(tab).closest(MSIQ_SELECTORS.bureauContent).text() || $(tab).next().text();
    const match = content.match(/(\d{3})/);
    if (match) {
      const score = parseInt(match[1]);
