              name: 'Top Tier Financial Solutions',
              address: '2141 Cortelyou Road',
              city: 'Brooklyn',
              state: 'NY',
              zip: '11226',
              email: 'info@toptierfinancialsolutions.com',
              phone: '(347) 699-4664',
              officePhone: '(800) 478-7119',
              fax: '(718) 489-4145',
              website: 'https://www.toptierfinancialsolutions.com',
              preparedBy: 'Frantz Chery',
            },
          };

