// Credit report source detection - identifies which monitoring service generated the file

export type CreditReportSource = 
  | 'identityiq'
  | 'smartcredit'
  | 'privacyguard'
  | 'myscoreiq'
  | 'creditkarma'
  | 'annualcreditreport'
  | 'experian'
  | 'transunion'
  | 'equifax'
  | 'unknown';

export interface SourceDetectionResult {
  source: CreditReportSource;
  confidence: 'high' | 'medium' | 'low';
  detectedBureau?: 'transunion' | 'experian' | 'equifax' | 'combined';
  signatures: string[];
}

// Signature patterns for each monitoring service
const SOURCE_SIGNATURES: Record<CreditReportSource, RegExp[]> = {
  identityiq: [
    /identityiq/i,
    /identity\s*iq/i,
    /idiq/i,
    /class="?iq-/i,
    /id="?iq-/i,
    /data-iq-/i,
    /IdentityIQ\.com/i,
    /Your\s+IdentityIQ\s+Report/i,
  ],
  smartcredit: [
    /smartcredit/i,
    /smart\s*credit/i,
    /class="?sc-/i,
    /smartcredit\.com/i,
    /SmartCredit\s+Report/i,
    /data-smartcredit/i,
  ],
  privacyguard: [
    /privacyguard/i,
    /privacy\s*guard/i,
    /class="?pg-/i,
    /privacyguard\.com/i,
    /PrivacyGuard\s+Report/i,
  ],
  myscoreiq: [
    /myscoreiq/i,
    /my\s*score\s*iq/i,
    /class="?msiq-/i,
    /myscoreiq\.com/i,
    /MyScoreIQ\s+Report/i,
  ],
  creditkarma: [
    /creditkarma/i,
    /credit\s*karma/i,
    /creditkarma\.com/i,
    /class="?ck-/i,
  ],
  annualcreditreport: [
    /annualcreditreport/i,
    /annual\s*credit\s*report/i,
    /annualcreditreport\.com/i,
    /Free\s+Annual\s+Credit\s+Report/i,
    /AnnualCreditReport\.com/i,
    /Disclosure\s+Report/i,
    /Your\s+Free\s+Credit\s+Report/i,
    /centralsource/i,
  ],
  experian: [
    /experian\.com/i,
    /Experian\s+Credit\s+Report/i,
    /class="?experian-/i,
    /class="?ex-/i,
    /data-experian/i,
    /FICO.*Score.*8/i,
    /Experian\s+Member/i,
    /experian\.com\/consumer/i,
    /Potentially\s+Negative\s+Information/i,
    /Your\s+Experian\s+Credit\s+Report/i,
  ],
  transunion: [
    /transunion\.com/i,
    /TransUnion\s+Credit\s+Report/i,
    /class="?tu-/i,
    /data-transunion/i,
    /VantageScore.*3\.0/i,
    /TransUnion\s+Member/i,
    /transunion\.com\/consumer/i,
    /TrueVision/i,
    /Your\s+TransUnion\s+Credit\s+Report/i,
    /Trade\s*Line\s*Information/i,
  ],
  equifax: [
    /equifax\.com/i,
    /myequifax\.com/i,
    /Equifax\s+Credit\s+Report/i,
    /class="?efx-/i,
    /class="?eq-/i,
    /data-equifax/i,
    /Equifax\s+Member/i,
    /equifax\.com\/personal/i,
    /Your\s+Equifax\s+Credit\s+Report/i,
    /Equifax\s+Core\s+Credit/i,
  ],
  unknown: [],
};

// Bureau detection patterns
const BUREAU_PATTERNS = {
  transunion: [/transunion/i, /trans\s*union/i, /\btruevision\b/i],
  experian: [/experian/i, /\bexperian\s+member\b/i],
  equifax: [/equifax/i, /\bmyequifax\b/i],
};

export function detectCreditReportSource(content: string): SourceDetectionResult {
  const matchedSignatures: string[] = [];
  let bestSource: CreditReportSource = 'unknown';
  let bestMatchCount = 0;

  // Check each source's signatures
  for (const [source, patterns] of Object.entries(SOURCE_SIGNATURES)) {
    if (source === 'unknown') continue;

    let matchCount = 0;
    for (const pattern of patterns) {
      if (pattern.test(content)) {
        matchCount++;
        matchedSignatures.push(`${source}: ${pattern.source}`);
      }
    }

    if (matchCount > bestMatchCount) {
      bestMatchCount = matchCount;
      bestSource = source as CreditReportSource;
    }
  }

  // Determine confidence based on match count
  let confidence: 'high' | 'medium' | 'low';
  if (bestMatchCount >= 3) {
    confidence = 'high';
  } else if (bestMatchCount >= 1) {
    confidence = 'medium';
  } else {
    confidence = 'low';
  }

  // Detect bureau
  const detectedBureau = detectBureau(content);

  return {
    source: bestSource,
    confidence,
    detectedBureau,
    signatures: matchedSignatures,
  };
