  if (bureausFound.length === 0) {
    return undefined;
  } else if (bureausFound.length === 1) {
    return bureausFound[0] as 'transunion' | 'experian' | 'equifax';
  } else if (bureausFound.length >= 2) {
    return 'combined';
  }

  return undefined;
}

